module mux2to1_singlebit (
    input sel,
    input in0,
    input in1,
    output out
);

    reg unused_mux_out;  // Multiplexer output register

    always @(*) begin
        case (sel)
            1'b0: unused_mux_out = in0;
            1'b1: unused_mux_out = in1;
            default: unused_mux_out = 1'b0;  // Default case (should not occur)
        endcase
    end

    assign out = unused_mux_out;

endmodule
